class Solution:
    def productQueries(self, n, queries):
        MOD = 10**9 + 7
        powers = []
        b = 0
        while n > 0:
            if n & 1:
                powers.append(1 << b)
            n >>= 1
            b += 1
        ans = []
        for l, r in queries:
            p = 1
            for j in range(l, r + 1):
                p = (p * powers[j]) % MOD
            ans.append(p)
        return ans

