class Solution:
    def productQueries(self, n, queries):
        MOD = 10**9 + 7
        exps = []
        b = 0
        while n > 0:
            if n & 1:
                exps.append(b)
            n >>= 1
            b += 1
        prefix = [0] * (len(exps) + 1)
        for i, e in enumerate(exps):
            prefix[i + 1] = prefix[i] + e
        ans = []
        for l, r in queries:
            total_exp = prefix[r + 1] - prefix[l]
            ans.append(pow(2, total_exp, MOD))
        return ans

