var productQueries = function(n, queries) {
    const MOD = 1000000007n;
    const exps = [];
    let b = 0;
    let m = n;
    while (m > 0) {
        if (m & 1) exps.push(b);
        m >>= 1;
        b++;
    }
    const prefix = new Array(exps.length + 1).fill(0);
    for (let i = 0; i < exps.length; i++) prefix[i + 1] = prefix[i] + exps[i];
    const modpow = (base, exp) => {
        let result = 1n;
        base %= MOD;
        while (exp > 0n) {
            if (exp & 1n) result = (result * base) % MOD;
            base = (base * base) % MOD;
            exp >>= 1n;
        }
        return result;
    };
    const ans = [];
    for (const [l, r] of queries) {
        const totalExp = BigInt(prefix[r + 1] - prefix[l]);
        ans.push(Number(modpow(2n, totalExp)));
    }
    return ans;
};
